// Test_StrategyTypeRecursiveParagraph 测试递归段落分块策略
// go test -v -run Test_StrategyTypeRecursiveParagraph ./
func Test_StrategyTypeRecursiveParagraph(t *testing.T) {
	factory := GetStrategyFactory()
	strategy, flag := factory.GetStrategy(StrategyTypeRecursiveParagraph)
	if !flag {
		t.Errorf("获取策略 %s 失败: %s", StrategyTypeRecursiveParagraph, "non_existent")
	}

	// 修改规则示例 - 可以根据需要调整以下参数
	if rpStrategy, ok := strategy.(*RecursiveParagraphStrategy); ok {
		// 1. 设置段落分隔符 - 用于识别独立段落的标记，默认为"\n\n"
		rpStrategy.WithSeparator("\n\n")
		// 2. 设置最大分层深度 - 控制标题层级提取的深度，>0表示启用分层处理
		rpStrategy.WithMaxDepth(6) // 支持到6级标题
		// 3. 设置是否保留标题 - 控制是否从文本中提取标题信息
		rpStrategy.WithSaveTitle(true)
		// 4. 设置块大小 - 每个分块的最大字符数
		rpStrategy.ChunkSize = 500 // 增大块大小以减少分块数量
		// 5. 设置重叠比例 - 相邻块之间的重叠部分占块大小的比例
		rpStrategy.Overlap = 0.2 // 增加重叠以保持上下文连贯性
		// 6. 设置是否清理空格 - 移除多余的空格和换行符
		rpStrategy.TrimSpace = true // 启用空格清理以优化内容
		// 7. 设置是否清理多余点 - 移除连续的多个省略号
		rpStrategy.TrimEllipsis = true // 启用省略号清理
		// 8. 设置是否移除URL和邮箱 - 控制是否过滤文本中的URL和邮箱
		rpStrategy.TrimURLAndEmail = false // 保留URL和邮箱
		// 9. 设置并发数 - 控制分块处理的并发度
		rpStrategy.Concurrency = 0 // 0表示不使用并发
	}
	ctx := context.Background()
	chunks, err := strategy.Chunk(ctx, testText())
	if err != nil {
		t.Errorf("分块失败: %v", err)
		return
	}

	t.Logf("测试生成的切片数量: %d", len(chunks))
	for j, chunk := range chunks {
		// 优化格式，使用更清晰的结构和分隔符，便于大模型理解
		content := chunk.Content
		// 保持内容块的完整性，使用明确的分隔符
		t.Logf("切片 %d:\n标题: %s\n层级: %d\n内容:\n%s\n分页：%d\n---", j+1, chunk.Title, chunk.Depth, content, chunk.Page)
	}
}

